section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/modular-monolith.json",
  "type": "object",
  "title": "Modular monolith module spec",
  "required": [
    "spec_id",
    "modules",
    "linter_in_ci",
    "schema_per_module",
    "event_bus",
    "version",
    "last_reviewed"
  ],
  "additionalProperties": false,
  "properties": {
    "spec_id": {
      "type": "string",
      "pattern": "^mm-[a-z0-9-]+$"
    },
    "modules": {
      "type": "array",
      "minItems": 2,
      "items": {
        "type": "object",
        "required": [
          "name",
          "public_api",
          "schema"
        ],
        "properties": {
          "name": {
            "type": "string",
            "pattern": "^[a-z][a-z0-9_]+$"
          },
          "public_api": {
            "type": "string"
          },
          "schema": {
            "type": "string"
          }
        }
      }
    },
    "linter_in_ci": {
      "type": "boolean",
      "const": true
    },
    "schema_per_module": {
      "type": "boolean",
      "const": true
    },
    "event_bus": {
      "enum": [
        "in_process",
        "rabbitmq",
        "kafka",
        "redis_streams"
      ]
    },
    "version": {
      "type": "string",
      "pattern": "^\\d+\\.\\d+\\.\\d+$"
    },
    "last_reviewed": {
      "type": "string",
      "format": "date"
    }
  }
}
